import React from 'react';
import { Collapse, Navbar, NavbarToggler, NavbarBrand, Nav, NavItem, NavLink } from 'reactstrap';
import './Navbar.css'
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome'
interface NavbarItem {
    name: string,
    url: string
}

interface NavbarProps {
    brandImage: string
    brand: string
    item : NavbarItem[]
    color: string
    collapsed : Boolean
    toggleNavbar : () => void
    icons : []
}
const HeaderNavbar: React.FunctionComponent<NavbarProps> = (props) => {
    return (
        <div>
            <Navbar className="bg-color" color={props.color} light expand="md">
                <NavbarBrand href="/" className="mr-auto customized-navbar">
                    <em className="brandName">{props.brand}</em>
                    {props.icons.map((icon) => 
                        <FontAwesomeIcon icon={icon}></FontAwesomeIcon>
                    )}
                </NavbarBrand>
                <NavbarToggler onClick={props.toggleNavbar} className="mr-2" />
                <Collapse isOpen={!props.collapsed} navbar>
                    <Nav navbar className="ml-auto">
                    {props.item.map((each) => 
                        <NavItem key={each.name}>
                            <NavLink  href={each.url}>{each.name}</NavLink>
                        </NavItem>
                    )}
                    </Nav>
                </Collapse>
            </Navbar>
        </div>
    )

};

export default HeaderNavbar;
